const normalizeBaseUrl = (value) => {
  const raw = String(value || '').trim();
  if (!raw) return '';
  return raw.replace(/\/rest\/v1\/?$/i, '').replace(/\/+$/,'');
};

const input = $input.first()?.json || {};

// ВСТАВЬ СЮДА РЕАЛЬНЫЕ ЗНАЧЕНИЯ
const supabaseUrl = normalizeBaseUrl('https://YOUR_PROJECT.supabase.co');
const supabaseKey = String('YOUR_SUPABASE_SERVICE_ROLE_KEY').trim();
const subscriptionUrl = String('https://t.me/SkrabVarezkaPiling').trim();
const ykShopId = String('YOUR_YOOKASSA_SHOP_ID').trim();
const ykSecret = String('YOUR_YOOKASSA_SECRET_KEY').trim();
const paymentReturnUrl = String('https://YOUR_DOMAIN/thanks').trim();
const managersGroupChatId = String('-1003989386408').trim();
const adminUserId = String('7260765133').trim();

const config = {
  SUPABASE_URL: supabaseUrl,
  SUPABASE_REST_URL: supabaseUrl ? `${supabaseUrl}/rest/v1` : '',
  SUPABASE_SERVICE_ROLE_KEY: supabaseKey,
  SUPABASE_CONFIGURED: !!(
    supabaseUrl &&
    !supabaseUrl.includes('YOUR_PROJECT') &&
    supabaseKey &&
    !supabaseKey.includes('YOUR_SUPABASE')
  ),

  SUBSCRIPTION_URL: subscriptionUrl,
  MANAGERS_GROUP_CHAT_ID: managersGroupChatId,
  ADMIN_USER_ID: adminUserId,

  PAYMENT_PROVIDER: 'yookassa',
  YOOKASSA_SHOP_ID: ykShopId,
  YOOKASSA_SECRET_KEY: ykSecret,
  PAYMENT_RETURN_URL: paymentReturnUrl,
  PAYMENT_CURRENCY: 'RUB',
  PAYMENTS_CONFIGURED: !!(
    ykShopId &&
    !ykShopId.includes('YOUR_YOOKASSA') &&
    ykSecret &&
    !ykSecret.includes('YOUR_YOOKASSA') &&
    paymentReturnUrl &&
    !paymentReturnUrl.includes('YOUR_DOMAIN')
  ),

  UPSELL_STANDARD_KEY: 'upsell_standard',
  UPSELL_STANDARD_LABEL: 'Апгрейд CH-spa',
  UPSELL_STANDARD_AMOUNT: 1990,
  UPSELL_STANDARD_PRICE_LABEL: '1990 ₽',

  WARMUP_ENABLED: true
};

return [{
  json: {
    ...input,
    ...config,
    app_config: config,
    raw: input.raw || input
  }
}];

const store = $getWorkflowStaticData('global');
store.users = store.users || {};
store.submissions = store.submissions || {};
store.payments = store.payments || {};
store.events = store.events || [];

const appConfig = $items('App Config', 0, 0)[0]?.json?.app_config || $items('App Config', 0, 0)[0]?.json || {};

for (const item of items) {
  const raw = item.json.raw || item.json;
  const msg = raw.message || item.json.message || {};
  const cb = raw.callback_query || item.json.callback_query || {};
  const from = msg.from || cb.from || {};
  const chatId = msg.chat?.id || cb.message?.chat?.id || from.id || null;
  const key = chatId !== null ? String(chatId) : null;
  const text = msg.text || '';
  const callbackData = cb.data || '';
  const hasPhoto = Array.isArray(msg.photo) && msg.photo.length > 0;
  const contact = msg.contact || {};
  const phoneFromText = text && /^\+?\d[\d\s\-()]{8,}$/.test(text.trim()) ? text.replace(/[^\d+]/g, '') : '';

  if (key) {
    const existing = store.users[key] || {};
    store.users[key] = {
      chatId,
      username: from.username || existing.username || '',
      firstName: from.first_name || existing.firstName || '',
      lastName: from.last_name || existing.lastName || '',
      phone: contact.phone_number || phoneFromText || existing.phone || '',
      state: existing.state || 'new',
      previousState: existing.previousState || 'new',
      selectedLevelKey: existing.selectedLevelKey || '',
      selectedLevelLabel: existing.selectedLevelLabel || '',
      giftValue: existing.giftValue || 0,
      lastPhoto: existing.lastPhoto || null,
      lastSubmissionId: existing.lastSubmissionId || null,
      lastApprovedSubmissionId: existing.lastApprovedSubmissionId || null,
      currentFlow: existing.currentFlow || 'purchase',
      currentReviewId: existing.currentReviewId || null,
      giftsUnlocked: existing.giftsUnlocked || false,
      createdAt: existing.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      lastSeenAt: new Date().toISOString(),
      lastMessageText: text || existing.lastMessageText || '',
      lastCallbackData: callbackData || existing.lastCallbackData || '',
      stepLabel: existing.stepLabel || '',
      source: existing.source || 'telegram'
    };

    item.json.crm = {
      telegram_user_id: from.id || null,
      telegram_chat_id: chatId,
      username: from.username || '',
      first_name: from.first_name || '',
      last_name: from.last_name || '',
      phone_raw: contact.phone_number || phoneFromText || '',
      phone_normalized: contact.phone_number || phoneFromText || '',
      state: store.users[key].state,
      previous_state: store.users[key].previousState,
      current_flow: store.users[key].currentFlow,
      selected_package_key: store.users[key].selectedLevelKey,
      selected_package_label: store.users[key].selectedLevelLabel,
      selected_package_gift_value: store.users[key].giftValue,
      gifts_unlocked: store.users[key].giftsUnlocked,
      updated_at: new Date().toISOString(),
      last_seen_at: new Date().toISOString()
    };
  }

  item.json.raw = raw;
  item.json.message = msg;
  item.json.callback_query = cb;
  item.json.telegram_chat_id = chatId;
  item.json.telegram_user_id = from.id || null;
  item.json.app_config = appConfig;

  store.events.push({
    at: new Date().toISOString(),
    chatId,
    text,
    callbackData,
    hasPhoto,
    hasContact: !!contact.phone_number
  });
}

if (store.events.length > 5000) store.events = store.events.slice(-5000);
return items;

