const msg = $json.message || {};
const chatId = msg.chat?.id;

if (!chatId) {
  throw new Error('chatId not found');
}

const photos = Array.isArray(msg.photo) ? msg.photo : [];
const bestPhoto = photos.length ? photos[photos.length - 1] : null;

const doc = msg.document || null;
const docMime = String(doc?.mime_type || '').toLowerCase();
const docName = String(doc?.file_name || '').toLowerCase();
const isImageDocument =
  !!doc &&
  (
    docMime.startsWith('image/') ||
    docName.endsWith('.jpg') ||
    docName.endsWith('.jpeg') ||
    docName.endsWith('.png') ||
    docName.endsWith('.webp')
  );

const fileId =
  bestPhoto?.file_id ||
  (isImageDocument ? doc.file_id : null);

if (!fileId) {
  throw new Error('Photo or image document not found in message');
}

const key = String(chatId);
const user = store.users[key] || { chatId };

user.lastPhoto = {
  fileId,
  fileUniqueId: bestPhoto?.file_unique_id || doc?.file_unique_id || '',
  sourceType: bestPhoto ? 'message.photo' : 'message.document',
  savedAt: new Date().toISOString()
};

user.previousState = user.state || 'awaiting_photo';
user.state = 'waiting_review';
user.stepLabel = 'Фото получено';
user.updatedAt = new Date().toISOString();

store.users[key] = user;

return [{
